import React from 'react'
import PropTypes from 'prop-types'

//Use border on all variations to enforce consistent sizing
const baseCSS = 'py-2 px-4 rounded border'

//Tailwind uses PurgeCSS
const variations = {
    contained: {
        primary:
            'bg-primary-900 text-slate-50 dark:bg-primary-50 dark:text-slate-900 focus:outline-primary-900/30 dark:focus:outline-primary-50/30 focus:outline',
    },
    outline: {
        primary:
            'dark:text-slate-50 dark:border-primary-50 border-primary-900 text-slate-900 focus:outline-primary-900/30 dark:focus:outline-primary-50/30 focus:outline',
    },
    text: {
        primary: 'dark:text-slate-50 text-slate-900 border-transparent',
    },
}

export const Button = React.forwardRef(
    ({ color = 'primary', children, variant = 'text', className = '', ...props }, ref) => {
        return (
            <button
                ref={ref}
                className={`font-medium ${baseCSS} ${variations[variant][color]} ${className ?? ''}`.trim()}
                {...props}
            >
                {children}
            </button>
        )
    }
)
Button.displayName = 'Button'

Button.propTypes = {
    darkMode: PropTypes.bool,
    class: PropTypes.string,
    className: PropTypes.string,
    color: PropTypes.oneOf(['inherit', 'primary']),
    variant: PropTypes.oneOf(['outline', 'contained', 'text']),
    children: PropTypes.node,
}
