import React from 'react'
import PropTypes from 'prop-types'
import * as T from 'three'
import { ComputeShaderPass } from '/src/graphics/gl'
import glslCollisionPass from '/src/distance-field-page/glslCollisionPass'
import glslLightingPass from '/src/distance-field-page/glslLightingPass'

export class DistanceFieldScene extends React.Component {
    constructor(props) {
        super(props)
        this.container = React.createRef()
        this.dragging = false
    }
    componentDidMount = () => {
        this.needsUpdate = true
        this.orbit = {
            d: 5,
            phi: Math.PI * 0.5,
            theta: Math.PI * 0.3,
            lookAtPoint: new T.Vector3(0, 0, 0),
        }
        this.camera = new T.PerspectiveCamera(this.props.fov, this.width / this.height, 1, 1000)
        this.updateCamera()

        this.envTextureLoader = new T.TextureLoader()
        this.uniforms = {
            zoomScale: {
                type: 'f',
                value: 0.4,
            },
            time: {
                type: 'f',
                value: this.props.time ?? 0,
            },
            invProjectionMat: {
                type: 'm4',
                value: this.camera.projectionMatrix.invert(),
            },
            cameraMat: {
                type: 'm4',
                value: this.camera.matrix,
            },
            occlusionDistance: {
                type: 'flaot',
                value: this.props.occlusionDistance ?? 0,
            },
            envMap: {
                type: 't',
                value: this.confEnvTexture(this.envTextureLoader.load(`/images/env-maps/${this.props.envMap}`)),
            },
        }
        this.collisionPass = new ComputeShaderPass(
            {
                uniforms: this.uniforms,
                fragmentShader: this.getCollisionShader(this.props),
            },
            this.width,
            this.height
        )
        this.lightingPass = new ComputeShaderPass(
            {
                uniforms: {
                    ...this.uniforms,
                    surfaceData: {
                        type: 't',
                        value: this.collisionPass.texTarget.t.texture,
                    },
                },
                fragmentShader: this.getLightingShader(this.props),
            },
            this.width,
            this.height,
            null,
            this.collisionPass.renderer
        )
        this.container.current.appendChild(this.collisionPass.renderer.domElement)
        this.attachOrbitControls()

        const animate = () => {
            requestAnimationFrame(animate)
            if (this.collisionPass) {
                this.delayResize()
                this.draw()
            }
        }
        animate()
    }
    componentWillUnmount() {
        this.collisionPass.dispose()
        this.lightingPass.dispose()
        delete this.collisionPass
        delete this.lightingPass
    }
    shouldComponentUpdate(nextProps) {
        this.updateCameraFov(nextProps.fov)
        this.uniforms.time.value = nextProps.time ?? 0
        this.uniforms.occlusionDistance.value = nextProps.occlusionDistance

        if (nextProps.glslSettings !== this.props.glslSettings || nextProps.glslLive !== this.props.glslLive) {
            this.updateProgram(nextProps)
        }
        if (nextProps.envMap !== this.props.envMap) {
            this.updateEnvMap(nextProps.envMap)
        }
        return false
    }
    render() {
        //Do not resize -- it slows down all elements on some systems
        return <div ref={this.container} className="w-full h-full flex items-center justify-center" />
    }

    get width() {
        return this.container.current?.getBoundingClientRect()?.width ?? 0
    }
    get height() {
        return this.container.current?.getBoundingClientRect()?.height ?? 0
    }
    get needsResize() {
        if (!this.collisionPass) {
            return false
        }
        const rendererBounds = this.collisionPass.renderer.domElement.getBoundingClientRect()
        return rendererBounds.width !== this.width || rendererBounds.height !== this.height
    }
    getCollisionShader(props) {
        return [props.glslSettings.trim(), props.glslLive, glslCollisionPass.trim()].join('\n')
    }
    getLightingShader(props) {
        return [props.glslSettings.trim(), props.glslLive, glslLightingPass.trim()].join('\n')
    }
    setCameraPosition() {
        const { d, phi, theta } = this.orbit
        this.camera.position.set(
            d * Math.cos(phi) * Math.sin(theta),
            d * Math.cos(theta),
            d * Math.sin(phi) * Math.sin(theta)
        )
    }
    updateCamera() {
        this.setCameraPosition()
        this.camera.lookAt(this.orbit.lookAtPoint)
        this.camera.updateMatrix()
    }
    updateCameraFov(fov) {
        this.camera.fov = fov
        this.camera.updateProjectionMatrix()
        this.uniforms.invProjectionMat.value = this.camera.projectionMatrix.invert()
    }
    draw() {
        this.collisionPass.execute(false)

        let programs = this.collisionPass.renderer.info.programs
        if (this.checkAndHandleProgramError(programs[programs.length - 1].diagnostics)) {
            return
        }

        this.lightingPass.execute(true)
        this.props.onDrawFinish && this.props.onDrawFinish(this.collisionPass.renderer.domElement)
    }
    checkAndHandleProgramError(diagnostics) {
        if (!diagnostics || !this.props.onProgramError) {
            return false
        }

        const {
            fragmentShader: { log },
        } = diagnostics
        const errors = []
        const nGlslSettingsLines = this.props.glslSettings.split('\n').length
        for (const line of log.split('\n')) {
            if (line.indexOf('ERROR') === -1) {
                continue
            }
            const [column, row, code, text] = line.substring(7).split(':')

            errors.push({
                column: parseInt(column),
                row: parseInt(row) - nGlslSettingsLines - 1,
                code,
                text,
            })
        }
        if (errors.length > 0) {
            this.props.onProgramError(errors)
            return true
        }
        return false
    }
    updateProgram(props) {
        this.collisionPass.updateFragmentShaderCleanly(this.getCollisionShader(props))
        this.lightingPass.updateFragmentShaderCleanly(this.getLightingShader(props))
    }
    orbitTheta(angle) {
        const { theta } = this.orbit
        const scaler = this.uniforms.zoomScale.value < 1 ? Math.pow(this.uniforms.zoomScale.value, 0.75) : 1
        this.orbit.theta = T.Math.clamp(theta + scaler * angle, 1e-3, Math.PI - 1e-3)
    }
    orbitPhi(angle) {
        let { phi } = this.orbit
        const scaler = this.uniforms.zoomScale.value < 1 ? Math.pow(this.uniforms.zoomScale.value, 0.75) : 1
        phi += angle * scaler
        if (phi > 2 * Math.PI) {
            phi -= 2 * Math.PI
        } else if (phi < 0) {
            phi += 2 * Math.PI
        }
        this.orbit.phi = phi
    }
    zoom(amount) {
        if (!this.collisionPass) {
            return
        }
        const currentZoom = this.uniforms.zoomScale.value
        this.uniforms.zoomScale.value = T.Math.clamp(currentZoom + 0.01 * currentZoom * amount, 1e-7, 2)
    }
    attachOrbitControls() {
        const domElement = this.collisionPass.renderer.domElement
        domElement.addEventListener('mousedown', (e) => {
            if (e.which == 1) {
                this.dragging = true
                this.mousePos = [e.pageX, e.pageY]
            } else {
                this.dragging = false
            }
        })
        domElement.addEventListener('mousemove', (e) => {
            if (!this.dragging) {
                return
            }
            e.preventDefault()
            e.stopPropagation()

            const { mousePos } = this
            const deltaX = (e.pageX - mousePos[0]) / this.width
            const deltaY = (e.pageY - mousePos[1]) / this.height

            this.orbitPhi(2 * Math.PI * deltaX)
            this.orbitTheta(-Math.PI * deltaY)
            this.updateCamera()

            this.mousePos = [e.pageX, e.pageY]
        })
        domElement.addEventListener('mousewheel', (e) => {
            this.zoom(-e.wheelDelta / 120)
        })
        window.addEventListener('mouseup', () => {
            this.dragging = false
        })
        domElement.addEventListener('touchstart', (e) => {
            if (e.touches.length == 1) {
                e.preventDefault()
                this.dragging = true
                this.mousePos = [e.touches[0].pageX, e.touches[0].pageY]
            } else {
                //As soon as more than 1 finger is detected, stop dragging.
                this.dragging = false
                //Pinching
                if (e.touches.length == 2) {
                    e.preventDefault()
                    this.pinchPos = e.touches
                }
            }
        })
        window.addEventListener(
            'touchmove',
            (e) => {
                const { dragging, mousePos, pinchPos, width, height } = this
                if (dragging) {
                    e.preventDefault()
                    e.stopPropagation()
                    let deltaX = (e.touches[0].pageX - mousePos[0]) / width
                    let deltaY = (e.touches[0].pageY - mousePos[1]) / height
                    this.orbitPhi(2 * Math.PI * deltaX)
                    this.orbitTheta(-Math.PI * deltaY)
                    this.updateCamera()
                    this.mousePos = [e.touches[0].pageX, e.touches[0].pageY]
                    return
                }
                if (e.touches.length == 2) {
                    e.preventDefault()
                    let oldScale = Math.sqrt(
                        Math.pow(pinchPos[0].pageX - pinchPos[1].pageX, 2) +
                            Math.pow(pinchPos[0].pageY - pinchPos[1].pageY, 2)
                    )
                    let scale = Math.sqrt(
                        Math.pow(e.touches[0].pageX - e.touches[1].pageX, 2) +
                            Math.pow(e.touches[0].pageY - e.touches[1].pageY, 2)
                    )
                    let delta = scale - oldScale //Positive means fingers moved apart, negative means fingers moved together.
                    //Define 1 change 'unit' as the fingers moving half the minimum screen extent. Tweak after experimentation.
                    this.zoom((3 * (-delta * 2)) / Math.min(height, width))
                }
            },
            { passive: false }
        )
        window.addEventListener('touchend', () => {
            this.dragging = false
        })
    }
    delayResize() {
        if (this.resizeTimeout) {
            return
        }
        const { width, height } = this
        const { width: rWidth, height: rHeight } = this.collisionPass.renderer.domElement.getBoundingClientRect()
        if (width === rWidth && height === rHeight) {
            return
        }
        this.resizeTimeout = setTimeout(() => this.resize(), 400)
    }
    resize() {
        const { width, height } = this
        this.camera.aspect = width / height
        this.updateCameraFov(this.camera.fov)
        this.collisionPass.resize(width, height)
        this.lightingPass.resize(width, height)
        clearTimeout(this.resizeTimeout)
        delete this.resizeTimeout
    }
    updateEnvMap(envMap) {
        this.uniforms.envMap.value.dispose()
        this.uniforms.envMap.value = this.confEnvTexture(this.envTextureLoader.load(`/images/env-maps/${envMap}`))
    }
    confEnvTexture(texture) {
        texture.minFilter = texture.magFilter = T.LinearFilter
        texture.wrapS = texture.wrapT = T.ClampToEdgeWrapping
        return texture
    }
}

DistanceFieldScene.propTypes = {
    fov: PropTypes.number,
    glslSettings: PropTypes.string.isRequired,
    glslLive: PropTypes.string.isRequired,
    onProgramError: PropTypes.func,
    time: PropTypes.number,
    envMap: PropTypes.string,
    occlusionDistance: PropTypes.number,
    onDrawFinish: PropTypes.func,
}
