import React from 'react'
import PropTypes from 'prop-types'
import { Dialog as DialogPrimitive } from '@headlessui/react'

export const Dialog = ({ className, ...props }) => (
    <DialogPrimitive className={`fixed z-10 inset-0 ${className ?? ''}`.trim()} {...props} />
)
Dialog.propTypes = {
    className: PropTypes.string,
}

const Overlay = ({ className, ...props }) => (
    <DialogPrimitive.Overlay className={`flex fixed inset-0 bg-neutral-900/50 ${className ?? ''}`.trim()} {...props} />
)
Overlay.propTypes = {
    className: PropTypes.string,
}
Dialog.Overlay = Overlay

const Title = ({ className, ...props }) => (
    <DialogPrimitive.Title className={`text-lg font-medium ${className ?? ''}`.trim()} {...props} />
)
Title.propTypes = {
    className: PropTypes.string,
}
Dialog.Title = Title

const Content = ({ className, ...props }) => (
    <div className={`relative rounded-xl bg-white dark:bg-zinc-900 m-auto ${className ?? ''}`.trim()} {...props} />
)
Content.propTypes = {
    className: PropTypes.string,
}
Dialog.Content = Content
