import complexOps from '/src/graphics/gl/complex/shaders/ops'
import intersect from '/src/graphics/gl/geometry/shaders/intersect'
import camera from '/src/graphics/gl/camera/shaders/camera'
import sdfOps from '/src/graphics/gl/geometry/shaders/sdfOps'

export default (distanceProgram, distanceProgramLighting) =>
    `
${complexOps.trim()}


${sdfOps.trim()}


${intersect.trim()}


${camera.trim()}

vec2 getSphericalUV(in vec3 v) {
    float theta = acos(clamp(-v.y, -1., 1.));
    float phi = atan(v.z, v.x);
    return vec2(
        (1. + phi / M_PI) / 2.,
        theta / M_PI
    );
}

vec3 directionLightEmit(in vec3 direction, in vec3 lightPower, in vec4 normal) {
    return clamp(dot(normal.xyz, -direction), 0., 1.) * lightPower;
}

${distanceProgram.trim()}


bool intersectSdf(vec4 rayPos, vec4 rayDir, float tmin, float tmax, out float t, out float steps) {
    t = max(tmin, 1e-5);
    tmax = min(tmax, 1000.);

    float adaptiveThreshold = clamp(pow(zoomScale, 1.5) * 1e-2, 27e-8, 3e-3);

    for(int i = 1; i < MAX_STEPS; ++i) {
        float dist = getSdfFromCamera(rayPos, rayDir, t);
        float absDist = abs(dist);
        t += absDist;
        if(dist >= 1e5) {
            return false;
        }
        if(absDist <= adaptiveThreshold) {
            steps = float(i);
            return t >= tmin && t < tmax;
        }
    }
    return false;
}

void raySurfaceCollision() {
    gl_FragColor = vec4(-1.);

    vec4 rayPos = getCameraPos();
    vec4 rayDir = getCameraRay(vUv);

    float bbmin, bbmax;

    //Slice the scene with a cube
    if(intersectAABB(vec3(-5.), vec3(5.), rayPos.xyz, rayDir.xyz, bbmin, bbmax)) {
        float t, steps;
        if(intersectSdf(rayPos, rayDir, bbmin, bbmax, t, steps)) {
            gl_FragColor = vec4(steps, 0., 0., t);
        }
    }
}

float getDistanceFieldOcclusion(in vec4 pos, in vec4 normal) {
    if(OCCLUSION_SAMPLES < 1) {
        return 1.;
    }

    float occlusion = 0.;
    float norm = 0.;

    for(int i = 1; i <= OCCLUSION_SAMPLES; ++i) {
        float t = float(occlusionDistance) * (float(i * i) / float(OCCLUSION_SAMPLES * OCCLUSION_SAMPLES));
        //A normalization coefficient
        norm += t;

        float distance = sdf((pos + t * normal).xyz);

        occlusion += max(0., t - abs(distance));
    }
    return 1. - clamp(occlusion / norm, 0., 1.);
}

void lighting() {
    vec4 data = texture2D(surfaceData, vUv);
    if(data.w == -1.) {
        return;
    }
    vec4 rayPos = getCameraPos();
    vec4 rayDir = getCameraRay(vUv);
    vec4 startPos = rayPos + data.w * rayDir;
    vec4 normal = vec4(normalize(gradient(startPos.xyz)), 0.);
    normal *= dot(rayDir, normal) < 0. ? 1. : -1.;

    float ao = getDistanceFieldOcclusion(startPos, normal);

    vec3 envMapColor = texture2D(envMap, getSphericalUV(normal.xyz)).xyz;

    ${(distanceProgramLighting?.trim() ?? `gl_FragColor = vec4(ao * envMapColor, 1.);`).trim()}
}
    `.trim()
